  1	import * as React from 'react';
  2	import { IstioConfigItem } from '../../types/IstioConfigList';
  3	import { IRow, TableVariant, ThProps } from '@patternfly/react-table';
  4	import {
  5	  Card,
  6	  CardBody,
  7	  CardHeader,
  8	  EmptyState,
  9	  EmptyStateBody,
 10	  EmptyStateVariant,
 11	  Title,
 12	  TitleSizes,
 13	  TooltipPosition
 14	} from '@patternfly/react-core';
 15	import { ValidationObjectSummary } from '../Validations/ValidationObjectSummary';
 16	import { GVKToBadge } from '../VirtualList/Config';
 17	import { kialiStyle } from 'styles/StyleUtils';
 18	import { PFBadge } from '../Pf/PfBadges';
 19	import { IstioObjectLink } from '../Link/IstioObjectLink';
 20	import { SimpleTable } from 'components/Table/SimpleTable';
 21	import { getGVKTypeString, getIstioObjectGVK } from '../../utils/IstioConfigUtils';
 22	
 23	type IstioConfigCardProps = {
 24	  items: IstioConfigItem[];
 25	  name: string;
 26	};
 27	
 28	const emtpytStyle = kialiStyle({
 29	  padding: 0,
 30	  margin: 0
 31	});
 32	
 33	export const IstioConfigCard: React.FC<IstioConfigCardProps> = (props: IstioConfigCardProps) => {
 34	  const columns: ThProps[] = [{ title: 'Name' }, { title: 'Status', width: 10 }];
 35	
 36	  const noIstioConfig: React.ReactNode = (
 37	    <EmptyState variant={EmptyStateVariant.sm} className={emtpytStyle}>
 38	      <EmptyStateBody className={emtpytStyle} data-test="istio-config-empty">
 39	        No Istio Config found for {props.name}
 40	      </EmptyStateBody>
 41	    </EmptyState>
 42	  );
 43	
 44	  const overviewLink = (item: IstioConfigItem): React.ReactNode => {
 45	    return (
 46	      <IstioObjectLink
 47	        name={item.name}
 48	        namespace={item.namespace ?? ''}
 49	        cluster={item.cluster}
 50	        objectGVK={getIstioObjectGVK(item.apiVersion, item.kind)}
 51	      >
 52	        {item.name}
 53	      </IstioObjectLink>
 54	    );
 55	  };
 56	
 57	  const rows: IRow[] = props.items
 58	    .sort((a: IstioConfigItem, b: IstioConfigItem) => {
 59	      // TODO localCompare with apiVersion
 60	      if ((a.kind ?? '') < (b.kind ?? '')) {
 61	        return -1;
 62	      } else if ((a.kind ?? '') > (b.kind ?? '')) {
 63	        return 1;
 64	      } else {
 65	        return a.name < b.name ? -1 : 1;
 66	      }
 67	    })
 68	    .map((item, itemIdx) => {
 69	      return {
 70	        cells: [
 71	          <span>
 72	            <PFBadge
 73	              badge={GVKToBadge[getGVKTypeString(getIstioObjectGVK(item.apiVersion, item.kind))]}
 74	              position={TooltipPosition.top}
 75	            />
 76	            {overviewLink(item)}
 77	          </span>,
 78	          <ValidationObjectSummary
 79	            id={`${itemIdx}-config-validation`}
 80	            validations={item.validation ? [item.validation] : []}
 81	          />
 82	        ]
 83	      };
 84	    });
 85	
 86	  return (
 87	    <Card isCompact={true} id="IstioConfigCard">
 88	      <CardHeader actions={{ actions: <></>, hasNoOffset: false }}>
 89	        <Title headingLevel="h3" size={TitleSizes.lg}>
 90	          Istio Config
 91	        </Title>
 92	      </CardHeader>
 93	
 94	      <CardBody>
 95	        <SimpleTable
 96	          label="Istio Config List"
 97	          columns={columns}
 98	          rows={rows}
 99	          variant={TableVariant.compact}
100	          emptyState={noIstioConfig}
101	        />
102	      </CardBody>
103	    </Card>
104	  );
105	};

